// --- types.d.ts ---
// types.d.ts

export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

export interface WeatherMetricsProps {
  humidity: number;
  windSpeed: number;
  humidityLabel: string;
  windLabel: string;
}

export interface ForecastItemProps extends ForecastDay {
  unit: string;
}

export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit: string;
}

export interface WeatherHookReturn {
  formattedTemp: string;
  unitSuffix: string;
  humidityDisplay: string;
  windDisplay: string;
  forecastData: ForecastDay[];
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const WEATHER_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Snowy: '❄️',
  'Partly Cloudy': '⛅',
  Thunderstorm: '⛈️',
};

export const UNIT_LABELS: Record<string, { temp: string; wind: string }> = {
  metric: {
    temp: '°C',
    wind: 'km/h',
  },
  imperial: {
    temp: '°F',
    wind: 'mph',
  },
};

export const HUMIDITY_LABEL: string = 'Humidity';
export const WIND_SPEED_LABEL: string = 'Wind Speed';

export const DEFAULT_UNIT: string = 'metric';

// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useMemo } from 'react';
import type { WeatherProps, WeatherHookReturn } from './types';
import * as constants from './constants';

export function useComponent(props: WeatherProps): WeatherHookReturn {
  const {
    temperature,
    unit,
    humidity,
    windSpeed,
    forecast,
  } = props;

  return useMemo(() => ({
    formattedTemp: Math.round(temperature).toString(),
    unitSuffix: unit === 'imperial' ? '°F' : '°C',
    humidityDisplay: `${Math.round(humidity)}%`,
    windDisplay: `${Math.round(windSpeed)} ${unit === 'imperial' ? 'mph' : 'km/h'}`,
    forecastData: forecast,
  }), [temperature, unit, humidity, windSpeed, forecast]);
}


