// components/WeatherHeader.tsx — reusable sub-component
import React from 'react';
import { Row, Heading, Icon } from '@ggui-ai/design/primitives';
import { WeatherProps } from './types';

export function WeatherHeader(props: WeatherProps) {
  const { city, condition } = props;

  return (
    <Row
      align="center"
      justify="between"
      style={{
        padding: 'var(--ggui-spacing-4, 16px)',
        borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
      }}
    >
      <Heading level={2} color="var(--ggui-color-onSurface)">
        {city}
      </Heading>
      <Icon
        name={condition.toLowerCase()}
        color="var(--ggui-color-primary-500)"
      />
    </Row>
  );
}


// --- components/WeatherMetrics.tsx ---
// components/WeatherMetrics.tsx — reusable sub-component
import React from 'react';
import { Stack, Row, Text, Icon } from '@ggui-ai/design/primitives';
import type { WeatherMetricsProps } from './types';

export function WeatherMetrics({ humidity, windSpeed, humidityLabel, windLabel }: WeatherMetricsProps) {
  return (
    <Row gap="var(--ggui-spacing-6, 24px)" justify="center" align="center">
      {/* Humidity Metric */}
      <Stack align="center" gap="var(--ggui-spacing-1, 4px)">
        <Row align="center" gap="var(--ggui-spacing-2, 8px)">
          <Icon 
            name="water_drop" 
            size={20} 
            color="var(--ggui-color-primary-500, #0ea5e9)" 
          />
          <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
            {humidity}%
          </Text>
        </Row>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {humidityLabel}
        </Text>
      </Stack>

      {/* Wind Speed Metric */}
      <Stack align="center" gap="var(--ggui-spacing-1, 4px)">
        <Row align="center" gap="var(--ggui-spacing-2, 8px)">
          <Icon name="air" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
          <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
            {windSpeed} km/h
          </Text>
        </Row>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {windLabel}
        </Text>
      </Stack>
    </Row>
  );
}


// --- components/ForecastStrip.tsx ---
// components/ForecastStrip.tsx — reusable sub-component
import React from 'react';
import { Box, Row, Stack, Text } from '@ggui-ai/design/primitives';
import type { ForecastStripProps, ForecastItemProps } from './types';

function ForecastItem({ day, icon, high, low, unit }: ForecastItemProps) {
  return (
    <Stack align="center" gap="var(--ggui-spacing-1)">
      <Text variant="caption">{day}</Text>
      <Text variant="bodyLarge">{icon}</Text>
      <Row gap="var(--ggui-spacing-1)">
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {high}{unit}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {low}{unit}
        </Text>
      </Row>
    </Stack>
  );
}

export function ForecastStrip({ forecast, unit }: ForecastStripProps) {
  return (
    <Row
      justify="between"
      align="center"
      style={{
        padding: 'var(--ggui-spacing-4) 0',
        borderTop: '1px solid var(--ggui-color-outlineVariant)',
      }}
    >
      {forecast.map((item, index) => (
        <Box key={`${item.day}-${index}`}>
          <ForecastItem {...item} unit={unit} />
        </Box>
      ))}
    </Row>
  );
}


// --- ui.tsx ---
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import type { WeatherProps as Props, WeatherHookReturn as HookReturn } from './types';
import { WeatherMetrics } from './components/WeatherMetrics';
import { ForecastStrip } from './components/ForecastStrip';

export function Component(props: Props & HookReturn) {
  return (
    <Container maxWidth="400px">
      <Card
        style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}
        padding="var(--ggui-spacing-6, 24px)"
        shadow="md"
        radius="xl"
      >
        <Stack gap={24}>
          {/* Header & Current Weather */}
          <Stack gap={8} align="center">
            <Heading level={2} color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {props.city}
            </Heading>

            <Heading level={1} style={{ fontSize: '4.5rem', fontWeight: 'var(--ggui-font-weight-bold, 700)', lineHeight: 1 }}>
              {props.formattedTemp}{props.unitSuffix}
            </Heading>

            <Stack direction="horizontal" gap={8} align="center">
              <Icon size={24} color="var(--ggui-color-onSurfaceVariant, #52525b)">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <circle cx="12" cy="12" r="5" />
                  <path d="M12 1v2m0 18v2M4.22 4.22l1.42 1.42m12.72 12.72l1.42 1.42M1 12h2m18 0h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42" />
                </svg>
              </Icon>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {props.condition}
              </Text>
            </Stack>
          </Stack>

          {/* Metrics */}
          <WeatherMetrics
            humidity={props.humidity}
            windSpeed={props.windSpeed}
            humidityLabel="Humidity"
            windLabel="Wind Speed"
          />

          <Divider margin={0} />

          {/* Forecast */}
          <ForecastStrip
            forecast={props.forecastData}
            unit={props.unitSuffix}
          />
        </Stack>
      </Card>
    </Container>
  );
}


// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { Component } from './components/index';

export default function Entrypoint(props: Props) {
  const state = useComponent(props);
  return <Component {...props} {...state} />;
}
